func solve(n int64, edges [][]int64, k int64) int64 {
    type UF struct {
        parent []int64
        rank   []int64
        comp   int64
    }

    NewUF := func(n int64) *UF {
        parent := make([]int64, n)
        rank := make([]int64, n)
        var i int64
        for i = 0; i < n; i++ {
            parent[i] = i
            rank[i] = 0
        }
        return &UF{parent, rank, n}
    }

    var find func(uf *UF, x int64) int64
    find = func(uf *UF, x int64) int64 {
        if uf.parent[x] != x {
            uf.parent[x] = find(uf, uf.parent[x])
        }
        return uf.parent[x]
    }

    union := func(uf *UF, x, y int64) {
        rx := find(uf, x)
        ry := find(uf, y)
        if rx == ry {
            return
        }
        if uf.rank[rx] < uf.rank[ry] {
            uf.parent[rx] = ry
        } else if uf.rank[rx] > uf.rank[ry] {
            uf.parent[ry] = rx
        } else {
            uf.parent[ry] = rx
            uf.rank[rx]++
        }
        uf.comp--
    }

    connected := func(uf *UF, x, y int64) bool {
        return find(uf, x) == find(uf, y)
    }

    clone := func(uf *UF) *UF {
        p := make([]int64, len(uf.parent))
        r := make([]int64, len(uf.rank))
        copy(p, uf.parent)
        copy(r, uf.rank)
        return &UF{p, r, uf.comp}
    }

    ufAll := NewUF(n)
    for _, e := range edges {
        u1, v1 := e[0], e[1]
        if !connected(ufAll, u1, v1) {
            union(ufAll, u1, v1)
        }
    }
    if ufAll.comp != 1 {
        return -1
    }

    mustUF := NewUF(n)
    for _, e := range edges {
        if e[3] == 1 {
            u, v := e[0], e[1]
            if connected(mustUF, u, v) {
                return -1
            }
            union(mustUF, u, v)
        }
    }

    minMust := int64(1<<40)
    hasMust := false
    max_s := int64(0)
    for _, e := range edges {
        s := e[2]
        if s > max_s {
            max_s = s
        }
        if e[3] == 1 {
            hasMust = true
            if s < minMust {
                minMust = s
            }
        }
    }
    if !hasMust {
        minMust = 1 << 40
    }

    optionalEdges := make([][]int64, 0)
    for _, e := range edges {
        if e[3] == 0 {
            optionalEdges = append(optionalEdges, e)
        }
    }

    check := func(X int64) bool {
        if X > minMust {
            return false
        }

        uf := clone(mustUF)

        for _, e := range optionalEdges {
            if uf.comp == 1 {
                break
            }
            s_val := e[2]
            if s_val >= X {
                u, v := e[0], e[1]
                if !connected(uf, u, v) {
                    union(uf, u, v)
                }
            }
        }

        if uf.comp == 1 {
            return true
        }

        upgradesUsed := int64(0)
        for _, e := range optionalEdges {
            if uf.comp == 1 {
                break
            }
            s_val := e[2]
            if s_val < X && 2*s_val >= X {
                u, v := e[0], e[1]
                if !connected(uf, u, v) {
                    if upgradesUsed < k {
                        union(uf, u, v)
                        upgradesUsed++
                    }
                }
            }
        }

        return uf.comp == 1
    }

    low, high := int64(1), 2*max_s
    ans := int64(-1)
    for low <= high {
        mid := (low + high) / 2
        if check(mid) {
            ans = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return ans
}
