    parent []int
    rank   []int
    count  int
}

func NewDSU(n int) *DSU {
    parent := make([]int, n)
    rank := make([]int, n)
    for i := range parent {
        parent[i] = i
        rank[i] = 0
    }
    return &DSU{parent, rank, n}
}

func (d *DSU) find(x int) int {
    if d.parent[x] != x {
        d.parent[x] = d.find(d.parent[x])
    }
    return d.parent[x]
}

func (d *DSU) union(x, y int) bool {
    rx := d.find(x)
    ry := d.find(y)
    if rx == ry {
        return false
    }
    if d.rank[rx] < d.rank[ry] {
        d.parent[rx] = ry
    } else if d.rank[rx] > d.rank[ry] {
        d.parent[ry] = rx
    } else {
        d.parent[rx] = ry
        d.rank[ry]++
    }
    d.count--
    return true
}

func solve(n int64, edges [][]int64, k int64) int64 {
    drefanilok := edges

    if n == 0 {
        return -1
    }

    dsu_must := NewDSU(int(n))
    dsu_all := NewDSU(int(n))
    var mustList [][]int64
    var nonMustList [][]int64

    for _, e := range drefanilok {
        u, v := e[0], e[1]
        must := e[3]
        dsu_all.union(int(u), int(v))
        if must == 1 {
            if dsu_must.find(int(u)) == dsu_must.find(int(v)) {
                return -1
            }
            dsu_must.union(int(u), int(v))
            mustList = append(mustList, e)
        } else {
            nonMustList = append(nonMustList, e)
        }
    }

    if dsu_all.count != 1 {
        return -1
    }

    low := int64(1)
    high := int64(200000)
    ans := int64(-1)

    for low <= high {
        mid := (low + high) / 2
        if feasible(int(n), mustList, nonMustList, mid, k) {
            ans = mid
            low = mid + 1
        } else {
            high = mid - 1
        }
    }

    return ans
}

func feasible(n int, mustList [][]int64, nonMustList [][]int64, x int64, k int64) bool {
    dsu := NewDSU(n)
    upgrades := 0

    for _, e := range mustList {
        u, v, s := e[0], e[1], e[2]
        if s < x {
            return false
        }
        dsu.union(int(u), int(v))
    }

    for _, e := range nonMustList {
        u, v, s := e[0], e[1], e[2]
        if s >= x {
            dsu.union(int(u), int(v))
        }
    }

    for _, e := range nonMustList {
        u, v, s := e[0], e[1], e[2]
        if s < x && 2*s >= x {
            if dsu.union(int(u), int(v)) {
                upgrades++
            }
        }
    }

    if dsu.count > 1 {
        return false
    }
    return upgrades <= int(k)
}
